  const getAutoRecommendedInspector = (req: ClientRequest) => {
    if (!inspectors || inspectors.length === 0) return null;

    const normalizeAr = (str: string) => {
      if (!str) return "";
      return str
        .replace(/[أإآ]/g, "ا")
        .replace(/ة/g, "ه")
        .replace(/ى/g, "ي")
        .replace(/\s+/g, "")
        .toLowerCase();
    };

    const reqGov = normalizeAr(req.governorate);
    const reqCity = normalizeAr(req.city);

    // Filter inspectors by governorate first
    let candidates = inspectors.filter(
      (ins) => normalizeAr(ins.governorate) === reqGov,
    );

    // If no direct matching governorate, fall back to active ones
    if (candidates.length === 0) {
      candidates = inspectors.filter(
        (ins) => ins.status !== "SUSPENDED" && ins.status !== "BLOCKED",
      );
    }

    // Filter by specific zone/city contains
    const zoneCandidates = candidates.filter((ins) => {
      const insZone = normalizeAr(ins.zone || "");
      return insZone.includes(reqCity) || reqCity.includes(insZone);
    });

    if (zoneCandidates.length > 0) {
      candidates = zoneCandidates;
    }

    // Workload calculation
    const getInspectorWorkload = (insId: string) => {
      return (requests || []).filter(
        (r) =>
          r.assignedInspectorId === insId &&
          r.status !== "COMPLETED" &&
          r.status !== "CANCELLED",
      ).length;
    };

    let best = candidates[0];
    let minWorkload = getInspectorWorkload(best.id);

    for (let i = 1; i < candidates.length; i++) {
      const cand = candidates[i];
      const workload = getInspectorWorkload(cand.id);
      if (workload < minWorkload) {
        minWorkload = workload;
        best = cand;
      }
    }

    return best || null;
  };
