                          if (!matchSearch) return false;

                          if (verifyBadgeFilter === "VERIFIED" && !comp.isVerified) return false;
                          if (verifyBadgeFilter === "UNVERIFIED" && comp.isVerified) return false;

                          if (verifyRateFilter === "HIGH" && comp.rating < 4.5) return false;
                          if (verifyRateFilter === "MEDIUM" && (comp.rating < 4.0 || comp.rating >= 4.5)) return false;
                          if (verifyRateFilter === "LOW" && comp.rating >= 4.0) return false;

                          return true;
